    @SuppressLint("SetJavaScriptEnabled")
    private void configureWebView() {
        WebSettings settings = webView.getSettings();

        // JavaScript is required for our SPA – but we tightly control origins.
        settings.setJavaScriptEnabled(true);

        // Disable dangerous defaults
        settings.setAllowFileAccess(false);
        settings.setAllowFileAccessFromFileURLs(false);
        settings.setAllowUniversalAccessFromFileURLs(false);
        settings.setAllowContentAccess(false);
        settings.setGeolocationEnabled(false);          // we handle via bridge
        settings.setDatabaseEnabled(false);
        settings.setSaveFormData(false);
        settings.setSavePassword(false);

        // DOM storage needed for SPA
        settings.setDomStorageEnabled(true);

        // Disable mixed content
        settings.setMixedContentMode(WebSettings.MIXED_CONTENT_NEVER_ALLOW);

        // Cache – use default strategy
        settings.setCacheMode(WebSettings.LOAD_DEFAULT);

        // User-agent suffix so our backend can identify the native shell
        String defaultUA = settings.getUserAgentString();
        settings.setUserAgentString(defaultUA + " HybridApp/1.0");

        // ── JavaScript bridge (minimal surface) ──────────────
        webView.addJavascriptInterface(new SecureJsBridge(), "NativeBridge");

        // ── WebViewClient – origin & TLS enforcement ─────────
        webView.setWebViewClient(new SecureWebViewClient());

        // ── WebChromeClient – file chooser, console ──────────
        webView.setWebChromeClient(new SecureWebChromeClient());
    }

    // ================================================================
    //  Origin validation helper
