    private static boolean isAllowedUrl(String url) {
        if (url == null) return false;
        try {
            Uri uri = Uri.parse(url);
            String scheme = uri.getScheme();
            String host = uri.getHost();
            return "https".equalsIgnoreCase(scheme) && host != null && ALLOWED_HOSTS.contains(host.toLowerCase(Locale.ROOT));
        } catch (Exception e) {
            return false;
        }
    }

    private boolean isCallerAllowed() {
        String currentUrl = webView.getUrl();
        return isAllowedUrl(currentUrl);
    }

    private boolean rateLimitOk() {
        long now = System.currentTimeMillis();
        if (now - lastBridgeCallTimestamp < BRIDGE_CALL_MIN_INTERVAL_MS) {
            Log.w(TAG, "Bridge call rate-limited");
            return false;
        }
        lastBridgeCallTimestamp = now;
        return true;
    }

    // ================================================================
    //  JavaScript Bridge (annotated methods only)
