    private class SecureWebViewClient extends WebViewClient {

        /** Block navigation to non-allowed origins. */
        @Override
        public boolean shouldOverrideUrlLoading(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();
            if (isAllowedUrl(url)) {
                return false; // let WebView handle it
            }
            // For intent:// or market:// links, open externally with user consent
            if (url.startsWith("intent://") || url.startsWith("market://")) {
                try {
                    Intent intent = Intent.parseUri(url, Intent.URI_INTENT_SCHEME);
                    // Restrict to our own package or known safe packages
                    if (intent.resolveActivity(getPackageManager()) != null) {
                        startActivity(intent);
                    }
                } catch (Exception e) {
                    Log.w(TAG, "Could not resolve intent URL", e);
                }
                return true;
            }
            Log.w(TAG, "Blocked navigation to disallowed URL: " + url);
            return true; // block
        }

        /** Reject SSL errors – never call handler.proceed(). */
        @Override
        public void onReceivedSslError(WebView view, SslErrorHandler handler, SslError error) {
            Log.e(TAG, "SSL error – rejecting: " + error.toString());
            handler.cancel();
            showErrorPage("Security error: could not establish a secure connection.");
        }

        /** Block sub-resource loads from non-allowed origins. */
        @Nullable
        @Override
        public WebResourceResponse shouldInterceptRequest(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();
            if (!isAllowedUrl(url)) {
                Log.w(TAG, "Blocked sub-resource from disallowed origin: " + url);
                // Return empty response
                return new WebResourceResponse("text/plain", "UTF-8", null);
            }
            return super.shouldInterceptRequest(view, request);
        }

        @Override
        public void onReceivedError(WebView view, WebResourceRequest request, WebResourceError error) {
            super.onReceivedError(view, request, error);
            if (request.isForMainFrame()) {
                showErrorPage("Network error. Please check your connection.");
            }
        }

        @Override
        public void onPageStarted(WebView view, String url, Bitmap favicon) {
            super.onPageStarted(view, url, favicon);
            // Double-check origin on every page start
            if (!isAllowedUrl(url)) {
                view.stopLoading();
                Log.w(TAG, "Stopped loading disallowed page: " + url);
            }
        }
    }

    // ================================================================
