    private class SecureWebChromeClient extends WebChromeClient {

        /** File chooser for <input type="file"> */
        @Override
        public boolean onShowFileChooser(WebView webView, ValueCallback<Uri[]> callback,
                                         FileChooserParams params) {
            if (filePathCallback != null) {
                filePathCallback.onReceiveValue(null);
            }
            filePathCallback = callback;

            Intent chooserIntent = new Intent(Intent.ACTION_GET_CONTENT);
            chooserIntent.addCategory(Intent.CATEGORY_OPENABLE);
            chooserIntent.setType("image/*");
            startActivityForResult(Intent.createChooser(chooserIntent, "Select File"),
                    REQUEST_FILE_CHOOSER);
            return true;
        }

        /** Suppress geolocation prompts – we handle via bridge. */
        @Override
        public void onGeolocationPermissionsShowPrompt(String origin,
                                                        GeolocationPermissions.Callback callback) {
            callback.invoke(origin, false, false);
        }

        /** Log JS console messages in debug builds only. */
        @Override
        public boolean onConsoleMessage(ConsoleMessage consoleMessage) {
            if (BuildConfig.DEBUG) {
                Log.d(TAG, "JS: " + consoleMessage.message()
                        + " [" + consoleMessage.sourceId() + ":" + consoleMessage.lineNumber() + "]");
            }
            return true;
        }
    }

    // ================================================================
    //  Camera
    // ================================================================

    private void launchCamera() {
        Intent takePictureIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (takePictureIntent.resolveActivity(getPackageManager()) != null) {
            File photoFile = null;
            try {
                photoFile = createImageFile();
            } catch (IOException ex) {
                Log.e(TAG, "Error creating image file", ex);
            }
            if (photoFile != null) {
                Uri photoURI = FileProvider.getUriForFile(this,
                        getApplicationContext().getPackageName() + ".fileprovider",
                        photoFile);
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI);
                takePictureIntent.addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION);
                startActivityForResult(takePictureIntent, REQUEST_CAMERA_CAPTURE);
            }
        }
    }

    private File createImageFile() throws IOException {
        String timeStamp = new SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(new Date());
        String imageFileName = "JPEG_" + timeStamp + "_";
        File storageDir = getExternalFilesDir(null);
        File image = File.createTempFile(imageFileName, ".jpg", storageDir);
        cameraPhotoPath = image.getAbsolutePath();
        return image;
    }

    // ================================================================
    //  Location
    // ================================================================

    @SuppressLint("MissingPermission")
    private void fetchLocation() {
        LocationRequest locationRequest = new LocationRequest.Builder(
                Priority.PRIORITY_HIGH_ACCURACY, 5000)
                .setMaxUpdates(1)
                .build();

        fusedLocationClient.requestLocationUpdates(locationRequest, new LocationCallback() {
            @Override
            public void onLocationResult(@NonNull LocationResult locationResult) {
                fusedLocationClient.removeLocationUpdates(this);
                Location location = locationResult.getLastLocation();
                if (location != null && pendingLocationCallbackId != null) {
                    try {
                        JSONObject loc = new JSONObject();
                        loc.put("latitude", location.getLatitude());
                        loc.put("longitude", location.getLongitude());
                        loc.put("accuracy", location.getAccuracy());
                        loc.put("callbackId", pendingLocationCallbackId);
                        sendJsCallback("onLocationResult", loc.toString());
                    } catch (JSONException e) {
                        Log.e(TAG, "JSON error", e);
                    }
                }
            }
        }, Looper.getMainLooper());
    }

    // ================================================================
    //  Permissions result
    // ================================================================

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions,
                                           @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        boolean granted = grantResults.length > 0
                && grantResults[0] == PackageManager.PERMISSION_GRANTED;

        switch (requestCode) {
            case REQUEST_CAMERA_PERMISSION:
                if (granted) launchCamera();
                else sendJsCallback("onCameraError", errorJson("Camera permission denied"));
                break;
            case REQUEST_LOCATION_PERMISSION:
                if (granted) fetchLocation();
                else sendJsCallback("onLocationError", errorJson("Location permission denied"));
                break;
        }
    }

    // ================================================================
    //  Activity result
    // ================================================================

    @Override
    protected void onActivityResult(int requestCode, int resultCode, @Nullable Intent data) {
        super.onActivityResult(requestCode, resultCode, data);

        if (requestCode == REQUEST_FILE_CHOOSER) {
            if (filePathCallback != null) {
                Uri[] results = null;
                if (resultCode == Activity.RESULT_OK && data != null && data.getData() != null) {
                    results = new Uri[]{data.getData()};
                }
                filePathCallback.onReceiveValue(results);
                filePathCallback = null;
            }
        } else if (requestCode == REQUEST_CAMERA_CAPTURE) {
            if (resultCode == Activity.RESULT_OK && cameraPhotoPath != null) {
                Uri photoUri = FileProvider.getUriForFile(this,
                        getApplicationContext().getPackageName() + ".fileprovider",
                        new File(cameraPhotoPath));
                sendJsCallback("onCameraResult",
                        "{\"photoUri\":\"" + sanitizeForJson(photoUri.toString()) + "\"}");
            } else {
                sendJsCallback("onCameraError", errorJson("Camera capture cancelled"));
            }
        }
    }

    // ================================================================
    //  Helpers
    // ================================================================

    /**
     * Send a callback to JS in a safe manner.
     * The function name is validated against a whitelist.
     */
    private void sendJsCallback(String functionName, String jsonPayload) {
        // Whitelist of allowed JS callback names
        Set<String> allowedCallbacks = new HashSet<>(Arrays.asList(
                "onLocationResult", "onLocationError",
                "onCameraResult", "onCameraError",
                "onPaymentResult", "onPaymentError"
        ));
        if (!allowedCallbacks.contains(functionName)) {
            Log.w(TAG, "Blocked JS callback to unknown function: " + functionName);
            return;
        }
        // Ensure we're on the UI thread and the page is still on an allowed origin
        runOnUiThread(() -> {
            if (webView != null && isCallerAllowed()) {
                // Use evaluateJavascript for safety (no javascript: URL injection)
                String script = "if(typeof window." + functionName + " === 'function'){ window."
                        + functionName + "(" + jsonPayload + "); }";
                webView.evaluateJavascript(script, null);
            }
        });
    }

    private static String errorJson(String message) {
        try {
            JSONObject obj = new JSONObject();
            obj.put("error", message);
            return obj.toString();
        } catch (JSONException e) {
            return "{\"error\":\"unknown\"}";
        }
    }

    /** Basic JSON-string sanitisation to prevent injection. */
    private static String sanitizeForJson(String input) {
        if (input == null) return "";
        return input.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }

    private void showErrorPage(String message) {
        runOnUiThread(() -> {
            if (!isFinishing()) {
                new AlertDialog.Builder(SecureWebViewActivity.this)
                        .setTitle("Error")
                        .setMessage(message)
                        .setPositiveButton("Retry", (d, w) -> webView.loadUrl(BASE_URL))
                        .setNegativeButton("Close", (d, w) -> finish())
                        .setCancelable(false)
                        .show();
            }
        });
    }
